#include<bits/stdc++.h>
using namespace std;
int n,q,a[100010],fst[100010],lst[100010];
set<int> s[100010];
long long ans[100010];
struct info
{
    int x,y;
    bool tp;
    int k,t;
}op[800010];
int tot;
void update(int x,int t)
{
    int a,b;
    if(s[x].empty())
    {
        a=n+1;
        b=0;
    }
    else
    {
        a=(*s[x].begin());
        b=(*s[x].rbegin());
    }
    if(a!=fst[x])
    {
        op[++tot]=(info){x,fst[x],0,-1,t};
        op[++tot]=(info){x,fst[x]=a,0,1,t};
    }
    if(b!=lst[x])
    {
        op[++tot]=(info){x,lst[x],1,-1,t};
        op[++tot]=(info){x,lst[x]=b,1,1,t};
    }
}
long long tr[100010];
int stk[800010],tp;
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int k)
{
    if(x==0)
    {
        return;
    }
    stk[++tp]=x;
    for(int i=x;i<=n;i+=lowbit(i))
    {
        tr[i]+=k;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=tr[i];
    }
    return ans;
}
int getsum(int l,int r)
{
    return query(r)-query(l-1);
}
void clear()
{
    for(int i=1;i<=tp;i++)
    {
        for(int j=stk[i];j<=n;j+=lowbit(j))
        {
            tr[j]=0;
        }
    }
    tp=0;
}
bool cmp(info a,info b)
{
    return a.x<b.x;
}
void cdq(int l,int r)
{
    if(l>=r)
    {
        return;
    }
    int mid=(l+r)>>1;
    cdq(l,mid);
    cdq(mid+1,r);
    for(int i=r,j=mid;i>=mid+1;i--)
    {
        if(op[i].tp)
        {
            while(j>=l&&op[j].x>op[i].x)
            {
                if(!op[j].tp)
                {
                    add(op[j].y,op[j].k);
                }
                j--;
            }
            ans[op[i].t]+=op[i].k*getsum(1,op[i].y);
        }
    }
    clear();
    for(int i=mid+1,j=l;i<=r;i++)
    {
        if(!op[i].tp)
        {
            while(j<=mid&&op[j].x<op[i].x)
            {
                if(op[j].tp)
                {
                    add(op[j].y,op[j].k);
                }
                j++;
            }
            ans[op[i].t]+=op[i].k*getsum(op[i].y,n);
        }
    }
    clear();
    inplace_merge(op+l,op+mid+1,op+1+r,cmp);
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        s[a[i]].insert(i);
    }
    for(int i=1;i<=n;i++)
    {
        if(s[i].empty())
        {
            fst[i]=n+1;
            lst[i]=0;
        }
        else
        {
            fst[i]=(*s[i].begin());
            lst[i]=(*s[i].rbegin());
        }
        op[++tot]=(info){i,fst[i],0,1,0};
        op[++tot]=(info){i,lst[i],1,1,0};
    }
    scanf("%d",&q);
    for(int i=1;i<=q;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        if(a[x]==y)
        {
            continue;
        }
        s[a[x]].erase(x);
        update(a[x],i);
        a[x]=y;
        s[y].insert(x);
        update(a[x],i);
    }
    cdq(1,tot);
    printf("%lld\n",ans[0]);
    for(int i=1;i<=q;i++)
    {
        ans[i]+=ans[i-1];
        printf("%lld\n",ans[i]);
    }
    return 0;
}
